import{_ as s,c as a,o as r,a1 as i,j as e,a as t,t as o}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"Einführung: OpenCode Agent Skills | opencode-agent-skills","description":"Lernen Sie die Kernwerte und Hauptfunktionen von OpenCode Agent Skills kennen. Meistern Sie dynamische Skill-Erkennung, Kontext-Injektion, Komprimierungswiederherstellung und mehr – kompatibel mit Claude Code und automatischen Empfehlungen.","frontmatter":{"title":"Einführung: OpenCode Agent Skills | opencode-agent-skills","sidebarTitle":"Lassen Sie KI Ihre Skills verstehen","subtitle":"Einführung: OpenCode Agent Skills","description":"Lernen Sie die Kernwerte und Hauptfunktionen von OpenCode Agent Skills kennen. Meistern Sie dynamische Skill-Erkennung, Kontext-Injektion, Komprimierungswiederherstellung und mehr – kompatibel mit Claude Code und automatischen Empfehlungen.","tags":["Einstiegsleitfaden","Plugin-Einführung"],"prerequisite":[],"order":1},"headers":[],"relativePath":"de/joshuadavidthomas/opencode-agent-skills/start/what-is-opencode-agent-skills/index.md","filePath":"de/joshuadavidthomas/opencode-agent-skills/start/what-is-opencode-agent-skills/index.md"}'),d={name:"de/joshuadavidthomas/opencode-agent-skills/start/what-is-opencode-agent-skills/index.md"},u={tabindex:"0"};function h(l,n,g,c,k,p){return r(),a("div",null,[n[8]||(n[8]=i(`<h1 id="was-ist-opencode-agent-skills" tabindex="-1">Was ist OpenCode Agent Skills? <a class="header-anchor" href="#was-ist-opencode-agent-skills" aria-label="Permalink to &quot;Was ist OpenCode Agent Skills?&quot;">​</a></h1><h2 id="was-sie-nach-dem-lernen-tun-konnen" tabindex="-1">Was Sie nach dem Lernen tun können <a class="header-anchor" href="#was-sie-nach-dem-lernen-tun-konnen" aria-label="Permalink to &quot;Was Sie nach dem Lernen tun können&quot;">​</a></h2><ul><li>Den Kernwert des OpenCode Agent Skills Plugins verstehen</li><li>Die Hauptfunktionen und Features des Plugins beherrschen</li><li>Verstehen, wie Skills automatisch erkannt und geladen werden</li><li>Unterscheiden, wie sich dieses Plugin von anderen Skill-Management-Lösungen unterscheidet</li></ul><h2 id="ihre-aktuellen-herausforderungen" tabindex="-1">Ihre aktuellen Herausforderungen <a class="header-anchor" href="#ihre-aktuellen-herausforderungen" aria-label="Permalink to &quot;Ihre aktuellen Herausforderungen&quot;">​</a></h2><p>Vielleicht haben Sie bereits folgende Situationen erlebt:</p><ul><li><strong>Schwierige Skill-Verwaltung</strong>: Skills sind über verschiedene Projekte, Benutzerverzeichnisse und Plugin-Cache verstreut, und Sie können nicht den richtigen Skill finden</li><li><strong>Probleme mit langen Sitzungen</strong>: Nach langen Sitzungen werden zuvor geladene Skills aufgrund von Kontextkomprimierung ungültig</li><li><strong>Kompatibilitätsängste</strong>: Sorge, dass vorhandene Skills und Plugins nach der Migration von Claude Code nicht mehr verwendet werden können</li><li><strong>Wiederholte Konfiguration</strong>: Jedes Projekt erfordert eine neue Skill-Konfiguration, es gibt kein einheitliches Skill-Management-System</li></ul><p>Diese Probleme beeinflussen alle die Effizienz Ihrer Nutzung von KI-Assistenten.</p><h2 id="kernkonzept" tabindex="-1">Kernkonzept <a class="header-anchor" href="#kernkonzept" aria-label="Permalink to &quot;Kernkonzept&quot;">​</a></h2><p><strong>OpenCode Agent Skills</strong> ist ein Plugin-System, das dynamische Skill-Erkennung und Verwaltungsfunktionen für OpenCode bereitstellt.</p><div class="info custom-block"><p class="custom-block-title">Was ist ein Skill?</p><p>Ein Skill ist ein wiederverwendbares Modul, das KI-Arbeitsablauf-Anleitungen enthält. Es ist normalerweise ein Verzeichnis mit einer <code>SKILL.md</code>-Datei (beschreibt die Funktionen und Verwendungsmethoden des Skills) sowie möglichen Hilfsdateien (Dokumentation, Skripte, etc.).</p></div><p><strong>Kernwert</strong>: Durch das standardisierte Skill-Format (SKILL.md) wird die Skill-Wiederverwendung über Projekte und Sitzungen hinweg ermöglicht.</p><h3 id="technische-architektur" tabindex="-1">Technische Architektur <a class="header-anchor" href="#technische-architektur" aria-label="Permalink to &quot;Technische Architektur&quot;">​</a></h3><p>Das Plugin basiert auf TypeScript + Bun + Zod und bietet 4 Kern-Tools:</p><table tabindex="0"><thead><tr><th>Tool</th><th>Funktion</th></tr></thead><tbody><tr><td><code>use_skill</code></td><td>Injiziert SKILL.md-Inhalt des Skills in den Sitzungskontext</td></tr><tr><td><code>read_skill_file</code></td><td>Liest Hilfsdateien im Skill-Verzeichnis (Dokumente, Konfigurationen, etc.)</td></tr><tr><td><code>run_skill_script</code></td><td>Führt ausführbare Skripte im Skill-Verzeichnis-Kontext aus</td></tr><tr><td><code>get_available_skills</code></td><td>Ruft die Liste der aktuell verfügbaren Skills ab</td></tr></tbody></table><h2 id="hauptfunktionen" tabindex="-1">Hauptfunktionen <a class="header-anchor" href="#hauptfunktionen" aria-label="Permalink to &quot;Hauptfunktionen&quot;">​</a></h2><h3 id="_1-dynamische-skill-erkennung" tabindex="-1">1. Dynamische Skill-Erkennung <a class="header-anchor" href="#_1-dynamische-skill-erkennung" aria-label="Permalink to &quot;1. Dynamische Skill-Erkennung&quot;">​</a></h3><p>Das Plugin erkennt Skills automatisch von mehreren Standorten und sortiert sie nach Priorität:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. .opencode/skills/              (Projekt-Ebene - OpenCode)</span></span>
<span class="line"><span>2. .claude/skills/                (Projekt-Ebene - Claude Code)</span></span>
<span class="line"><span>3. ~/.config/opencode/skills/     (Benutzer-Ebene - OpenCode)</span></span>
<span class="line"><span>4. ~/.claude/skills/              (Benutzer-Ebene - Claude Code)</span></span>
<span class="line"><span>5. ~/.claude/plugins/cache/        (Plugin-Cache)</span></span>
<span class="line"><span>6. ~/.claude/plugins/marketplaces/ (Installierte Plugins)</span></span></code></pre></div><p><strong>Regel</strong>: Das erste passende Skill wird verwendet, nachfolgende Skills mit demselben Namen werden ignoriert.</p><blockquote><p>Warum dieses Design?</p><p>Projekt-Ebene Skills haben Vorrang vor Benutzer-Ebene Skills, sodass Sie projektspezifisches Verhalten anpassen können, ohne die globale Konfiguration zu beeinflussen.</p></blockquote><h3 id="_2-kontext-injektion" tabindex="-1">2. Kontext-Injektion <a class="header-anchor" href="#_2-kontext-injektion" aria-label="Permalink to &quot;2. Kontext-Injektion&quot;">​</a></h3><p>Wenn Sie <code>use_skill</code> aufrufen, wird der Skill-Inhalt im XML-Format in den Sitzungskontext injiziert:</p><ul><li><code>noReply: true</code> - Die KI antwortet nicht auf die injizierte Nachricht</li><li><code>synthetic: true</code> - Markiert die Nachricht als systemgeneriert (nicht im UI angezeigt, nicht als Benutzereingabe gezählt)</li></ul><p>Dies bedeutet, dass der Skill-Inhalt dauerhaft im Sitzungskontext existiert. Selbst wenn die Sitzung wächst und eine Kontextkomprimierung durchführt, bleibt der Skill verfügbar.</p><h3 id="_3-komprimierungswiederherstellung" tabindex="-1">3. Komprimierungswiederherstellung <a class="header-anchor" href="#_3-komprimierungswiederherstellung" aria-label="Permalink to &quot;3. Komprimierungswiederherstellung&quot;">​</a></h3><p>Wenn OpenCode eine Kontextkomprimierung durchführt (eine häufige Operation bei langen Sitzungen), lauscht das Plugin auf das <code>session.compacted</code>-Ereignis und injiziert automatisch die Liste der verfügbaren Skills neu.</p><p>Dies stellt sicher, dass die KI in langen Sitzungen immer weiß, welche Skills verfügbar sind, und nicht durch Komprimierung die Skill-Zugriffsfähigkeit verliert.</p><h3 id="_4-claude-code-kompatibilitat" tabindex="-1">4. Claude Code Kompatibilität <a class="header-anchor" href="#_4-claude-code-kompatibilitat" aria-label="Permalink to &quot;4. Claude Code Kompatibilität&quot;">​</a></h3><p>Das Plugin ist vollständig kompatibel mit dem Claude Code Skill- und Plugin-System und unterstützt:</p><ul><li>Claude Code Skills (<code>.claude/skills/&lt;skill-name&gt;/SKILL.md</code>)</li><li>Claude Plugin Cache (<code>~/.claude/plugins/cache/...</code>)</li><li>Claude Plugin Marketplace (<code>~/.claude/plugins/marketplaces/...</code>)</li></ul><p>Das bedeutet, dass Sie, wenn Sie zuvor Claude Code verwendet haben, vorhandene Skills und Plugins nach der Migration zu OpenCode weiterhin verwenden können.</p><h3 id="_5-automatische-skill-empfehlung" tabindex="-1">5. Automatische Skill-Empfehlung <a class="header-anchor" href="#_5-automatische-skill-empfehlung" aria-label="Permalink to &quot;5. Automatische Skill-Empfehlung&quot;">​</a></h3><p>Das Plugin überwacht Ihre Nachrichten und verwendet semantische Ähnlichkeitserkennung, um festzustellen, ob diese mit einem verfügbaren Skill verwandt sind:</p><ul><li>Berechnet den Embedding-Vektor der Nachricht</li><li>Berechnet die Kosinus-Ähnlichkeit mit allen Skill-Beschreibungen</li><li>Wenn die Ähnlichkeit den Schwellenwert überschreitet, wird ein Evaluierungshinweis injiziert, der die KI empfiehlt, den entsprechenden Skill zu laden</li></ul><p>Dieser Prozess ist vollständig automatisch; Sie müssen sich Skill-Namen nicht merken oder explizit anfordern.</p><h3 id="_6-superpowers-integration-optional" tabindex="-1">6. Superpowers Integration (Optional) <a class="header-anchor" href="#_6-superpowers-integration-optional" aria-label="Permalink to &quot;6. Superpowers Integration (Optional)&quot;">​</a></h3><p>Das Plugin unterstützt den Superpowers-Workflow, aktiviert durch Umgebungsvariablen:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">true</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> opencode</span></span></code></pre></div><p>Nach Aktivierung erkennt das Plugin automatisch den <code>using-superpowers</code>-Skill und injiziert die vollständigen Workflow-Anleitungen bei der Sitzungsinitialisierung.</p><h2 id="vergleich-mit-anderen-losungen" tabindex="-1">Vergleich mit anderen Lösungen <a class="header-anchor" href="#vergleich-mit-anderen-losungen" aria-label="Permalink to &quot;Vergleich mit anderen Lösungen&quot;">​</a></h2>`,40)),e("table",u,[n[7]||(n[7]=e("thead",null,[e("tr",null,[e("th",null,"Lösung"),e("th",null,"Merkmale"),e("th",null,"Anwendungsszenarien")])],-1)),e("tbody",null,[n[4]||(n[4]=e("tr",null,[e("td",null,[e("strong",null,"opencode-agent-skills")]),e("td",null,"Dynamische Erkennung, Komprimierungswiederherstellung, automatische Empfehlung"),e("td",null,"Szenarien, die einheitliche Verwaltung und automatische Empfehlung erfordern")],-1)),e("tr",null,[n[2]||(n[2]=e("td",null,[e("strong",null,"opencode-skills")],-1)),e("td",null,[n[0]||(n[0]=t("Automatische Registrierung als ",-1)),e("code",null,"skills_"+o(l.name),1),n[1]||(n[1]=t(" Tool",-1))]),n[3]||(n[3]=e("td",null,"Szenarien, die unabhängige Tool-Aufrufe erfordern",-1))]),n[5]||(n[5]=e("tr",null,[e("td",null,[e("strong",null,"superpowers")]),e("td",null,"Vollständige Softwareentwicklungs-Workflows"),e("td",null,"Projekte, die strenge Prozessrichtlinien erfordern")],-1)),n[6]||(n[6]=e("tr",null,[e("td",null,[e("strong",null,"skillz")]),e("td",null,"MCP-Server-Modus"),e("td",null,"Szenarien, die plattformübergreifende Skill-Nutzung erfordern")],-1))])]),n[9]||(n[9]=i('<p>Gründe für die Auswahl dieses Plugins:</p><ul><li>✅ <strong>Zero-Konfiguration</strong>: Automatische Erkennung und Verwaltung von Skills</li><li>✅ <strong>Intelligente Empfehlung</strong>: Automatische Empfehlung relevanter Skills basierend auf semantischer Übereinstimmung</li><li>✅ <strong>Komprimierungswiederherstellung</strong>: Zuverlässig in langen Sitzungen</li><li>✅ <strong>Kompatibilität</strong>: Nahtlose Migration von Claude Code Skills</li></ul><h2 id="lektionszusammenfassung" tabindex="-1">Lektionszusammenfassung <a class="header-anchor" href="#lektionszusammenfassung" aria-label="Permalink to &quot;Lektionszusammenfassung&quot;">​</a></h2><p>Das OpenCode Agent Skills Plugin bietet durch dynamische Erkennung, Kontext-Injektion, Komprimierungswiederherstellung und andere Kernmechanismen eine vollständige Skill-Verwaltungsfunktion für OpenCode. Seine Kernwerte liegen in:</p><ul><li><strong>Automatisierung</strong>: Reduzierung der Belastung durch manuelle Konfiguration und das Merken von Skill-Namen</li><li><strong>Stabilität</strong>: Skills sind in langen Sitzungen immer verfügbar</li><li><strong>Kompatibilität</strong>: Nahtlose Integration in das bestehende Claude Code-Ökosystem</li></ul><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="./../installation/">Installation von OpenCode Agent Skills</a></strong>.</p><p>Sie werden lernen:</p><ul><li>Wie man das Plugin zur OpenCode-Konfiguration hinzufügt</li><li>Wie man überprüft, ob das Plugin korrekt installiert ist</li><li>Wie man den lokalen Entwicklungsmodus einrichtet</li></ul></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken Sie hier, um die Quellcode-Positionen anzuzeigen</strong></summary><blockquote><p>Aktualisiert am: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeile</th></tr></thead><tbody><tr><td>Plugin-Einstieg und Funktionsübersicht</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L1-L12" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>1-12</td></tr><tr><td>Liste der Kernfunktionen</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/README.md#L5-L11" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>5-11</td></tr><tr><td>Skill-Erkennungspriorität</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L241-L246" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>241-246</td></tr><tr><td>Synthetische Nachrichteninjektion</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L147-L162" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>147-162</td></tr><tr><td>Komprimierungswiederherstellungsmechanismus</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L144-L151" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>144-151</td></tr><tr><td>Semantisches Matching-Modul</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/embeddings.ts#L108-L135" target="_blank" rel="noreferrer"><code>src/embeddings.ts</code></a></td><td>108-135</td></tr></tbody></table><p><strong>Wichtige Konstanten</strong>:</p><ul><li><code>EMBEDDING_MODEL = &quot;Xenova/all-MiniLM-L6-v2&quot;</code>: Verwendetes Embedding-Modell</li><li><code>SIMILARITY_THRESHOLD = 0.35</code>: Schwellenwert für semantische Ähnlichkeit</li><li><code>TOP_K = 5</code>: Maximale Anzahl zurückgegebener Skills bei automatischer Empfehlung</li></ul><p><strong>Wichtige Funktionen</strong>:</p><ul><li><code>discoverAllSkills()</code>: Erkennt Skills von mehreren Positionen</li><li><code>use_skill()</code>: Injiziert Skill-Inhalt in den Sitzungskontext</li><li><code>matchSkills()</code>: Passt relevante Skills basierend auf semantischer Ähnlichkeit an</li><li><code>injectSyntheticContent()</code>: Injiziert synthetische Nachrichten in die Sitzung</li></ul></details>',10))])}const f=s(d,[["render",h]]);export{b as __pageData,f as default};
